using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // --- CalculateTotal: DataRow for inline constant combos ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 5, 0.15, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.20, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples for boundary / edge cases ---

    [TestMethod]
    [DynamicData(nameof(BoundaryTaxRateData))]
    public void CalculateTotal_WithBoundaryTaxRates_ReturnsExpectedTotal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, decimal expected)>
        BoundaryTaxRateData =>
    [
        (100m, 1, 0m, 100m),    // min tax rate
        (100m, 1, 1m, 200m),    // max tax rate (100%)
        (100m, 1, 0.5m, 150m),  // 50% tax
    ];

    // --- CalculateTotal: invalid inputs throw ---

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price")]
    public void CalculateTotal_WithNegativePrice_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    public void CalculateTotal_WithNegativeQuantity_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below zero")]
    [DataRow(1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_WithInvalidTaxRate_ThrowsArgumentOutOfRange(double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));
    }

    // --- ApplyDiscount: DynamicData with ValueTuples ---

    [TestMethod]
    [DynamicData(nameof(DiscountData))]
    public void ApplyDiscount_WithValidPercent_ReturnsDiscountedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)>
        DiscountData =>
    [
        (100m, 0m, 100m),       // no discount
        (100m, 10m, 90m),       // 10% off
        (100m, 50m, 50m),       // half off
        (100m, 100m, 0m),       // free
        (0m, 25m, 0m),          // zero price
        (199.99m, 15m, 169.9915m), // fractional result
    ];

    // --- ApplyDiscount: invalid discount throws ---

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Discount below zero")]
    [DataRow(100.01, DisplayName = "Discount above 100")]
    public void ApplyDiscount_WithInvalidPercent_ThrowsArgumentOutOfRange(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(50m, (decimal)discountPercent));
    }

    // --- FormatPrice: DataRow for simple string checks ---

    [TestMethod]
    [DataRow(19.99, "$", "$19.99")]
    [DataRow(0.00, "€", "€0.00")]
    [DataRow(1234.5, "£", "£1234.50")]
    public void FormatPrice_WithCurrencySymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPrice_DefaultSymbol_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(42.10m);

        Assert.StartsWith("$", result);
        Assert.AreEqual("$42.10", result);
    }
}

